    moveDuration: number = Game_Define.SYMBOL_FALL_DURATION
): Promise<void> {
    const symbolNode = this.GetSymbolNodeFromColRow(col, row);
    if (!symbolNode) {
        warn(`[SlotReel.StartFallSymbol] Symbol node not found at [col:${col}, row:${row}]`);
        return;
    }

    // 驗證參數
    if (count < 0) {
        warn(`[SlotReel.StartFallSymbol] Invalid count parameter: ${count}`);
        return;
    }

    if (symbolId < 0 || symbolId >= Game_Define.Symbol.MAX) {
        warn(`[SlotReel.StartFallSymbol] Invalid symbolId parameter: ${symbolId}, valid range: [0, ${Game_Define.Symbol.MAX})`);
        return;
    }

    // 顯示Symbol
    this.SetSymbolShow(col, row, true);

    // 位置計算優化：緩存位置，避免重複調用getPosition()
    const targetPos = symbolNode.getPosition();
    const offset = count * Game_Define.SymbolHeight;
    const startPos = v3(targetPos.x, targetPos.y + offset, targetPos.z);

    // 設定初始位置（落下起點）
    symbolNode.setPosition(startPos);

    // 切換Symbol
    this.ForceChangeSymbol(col, row, symbolId);

    await Define.Wait(this, delayTime);

    // 使用 tween 移動 Symbol 到目標位置（跟天降一樣的掉落速度）
    const duration = SYMBOL_ENTER_MOVE_TIME * count / Game_Define.ROW;
    await new Promise<void>(resolve => {
        const isSpecialSymbol = symbolId === Game_Define.Symbol.Scatter || symbolId === Game_Define.Symbol.SilverScatter || symbolId === Game_Define.Symbol.GoldScatter || symbolId === Game_Define.Symbol.Target || symbolId === Game_Define.Symbol.GoldTarget;
        const t = tween(symbolNode)
            .to(duration, { position: targetPos }, { easing: 'sineIn' })
            .call(() => {
                // 播放Symbol掉落音效
                AudioManager.Play(AudioManager.AudioClips.Symbol_Drop);
                // NearWin 模式下每顆落地都震動
                if (this.m_isHasScatterNearWin) {
                    this.m_gameView.BigHintShake(0.3, Game_Define.NEAR_WIN_SHAKE_DISTANCE);
                }
            });
        if (!isSpecialSymbol) {
            t.by(BOUNCE_UP_TIME, { position: v3(0, 6) })
             .by(BOUNCE_DOWN_TIME, { position: v3(0, -6) });
        }
        t.call(() => {
                symbolNode.setPosition(targetPos);
                resolve();
            })
            .start();
    });
}

