/**
 * 天降新符號
 * @param col 
 * @param row 
 * @param symbol 
 * @param left 該 col 天降新符號的數量
 * @returns 
 */
private EnterPlate( col: number, row: number, symbol: number, 
    left: number = Game_Define.ROW, mult: number, newColumnCell: SingleCell)
{
    let upperY = this.m_symbolSize.height * ( Game_Define.ROW + 0.5 ) + this.m_reelPositionOffset[ col ].y - this.m_viewSize.height / 2;

    let node = newColumnCell.ThisNode;
    //node.name = String( col * Game_Define.ROW + row );

    this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].ReFillSymbol(newColumnCell, symbol, row);


    //tools.SetOrderedZindex( node, col * Game_Define.ROW + ( Game_Define.ROW - 1 - row ) ); // 調整層級

    //node.getComponent( Sprite ).spriteFrame = this.GetRealSymbolSprite( symbol, mult );

    let pos = this.GetMiddleSymbolEmptyNodeFromColRow( col, row ).position;
    //從畫面可視最高的symbol開始往上加並依序排好
    let aboveY = this.m_symbolSize.height * ( left - 1 - row );
    let effectiveLeft = this.m_isHasScatterNearWin ? Math.max(left, Game_Define.ROW) : left;
    let newY = upperY + this.m_reelPositionOffset[ col ].y + this.m_symbolSize.height * ( effectiveLeft - 1 - row );
    node.setPosition( pos.x, newY );
    return new Promise<void>(
        ( resolve ) =>
        {
            let dropTime = SYMBOL_ENTER_MOVE_TIME * left / Game_Define.ROW;

            // Target spine 跟隨天降：掉落前掛到 node 上，落地後移到 effectNodes
            let targetSpineNode: Node = null;
            let targetPrefabKey: string = null;
            if (symbol === Game_Define.Symbol.Target || symbol === Game_Define.Symbol.GoldTarget) {
                const isGold = symbol === Game_Define.Symbol.GoldTarget;
                targetPrefabKey = isGold ? TARGET_SYMBOL_GOLD_PREFAB_KEY : TARGET_SYMBOL_PREFAB_KEY;
                targetSpineNode = PrefabPoolManager.GetInstance().GetNode(targetPrefabKey);
                if (targetSpineNode) {
                    targetSpineNode.setParent(node);
                    targetSpineNode.setPosition(0, 0, 0);
                    targetSpineNode.active = true;
                }
            }

            let stopCb = () =>
            {
                if (this.m_isHasScatterNearWin) this.m_gameView.BigHintShake(0.3, Game_Define.NEAR_WIN_SHAKE_DISTANCE);
                AudioManager.Play(AudioManager.AudioClips.Symbol_Drop);
                if (targetSpineNode) {
                    // 移到 effectNodes 並播 Stop→Idle
                    const worldPos = this.m_gameView.EffectPlate.GetSymbolNodeWorldPosPublic(col, row);
                    targetSpineNode.setParent(this.m_gameView.EffectPlate.GetEffctNode(Game_Define.LAYERS.SYMBOL));
                    targetSpineNode.setWorldPosition(worldPos);
                    const position = Common.GetPositionFromColRow(col, row);
                    this.m_gameView.EffectPlate.RegisterTargetStopNode(position, targetSpineNode, targetPrefabKey);
                    const spine = targetSpineNode.getComponent(BaseSpine);
                    if (spine) {
                        AudioManager.Play(symbol === Game_Define.Symbol.GoldTarget ? AudioManager.AudioClips.Target_Super : AudioManager.AudioClips.Target);
                        log(`[TargetDiag] ReFill-stopCb『播IN(Stop)』 col=${col} row=${row} symbol=${symbol}(${symbol === Game_Define.Symbol.GoldTarget ? 'Gold' : 'Normal'})`);
                        spine.PlayAnimation("Stop", spine.Spine, false).then(() => {
                            spine.PlayAnimation("Idle", spine.Spine, true);
                        });

